import path from "path";
import * as fs from "fs";
import { Binary } from "./Binary";
import { Config as ConfigClass } from './Config';
import { EmbeddedEngine } from './EmbeddedEngine';
import { EnvLoader } from './EnvLoader';
import { ProcessResponse, ResponseEngine } from "../@types/Engine";
import { BinaryType } from "../@types/Binary";
import { createRequire } from 'module';
import * as net from 'net';
import { spawn, ChildProcess } from "child_process";

// Almacén global de servidores TCP y conexiones persistentes
const globalTcpServers = new Map<string, { port: number, process: ChildProcess | null }>();

// Pool de sockets por base de datos: N conexiones al daemon con UNA petición
// en vuelo por socket. Con un único socket + cola FIFO, 100 queries de un
// Promise.all se ejecutaban en serie (~100 × RTT); con el pool corren en
// paralelo real contra el pool sqlx del daemon.
interface SocketPool {
    free: net.Socket[];
    total: number;
    waiters: Array<(s: net.Socket) => void>;
}
const socketPools = new Map<string, SocketPool>();
const CLIENT_POOL_SIZE = 10; // alineado con el pool sqlx del daemon

// Query Cache para evitar JSON.parse repetido
const queryCache = new Map<string, any>();
const MAX_CACHE_SIZE = 500;

class QueryEngine {
    private name: string;
    private config: any;
    private arguments: any;
    private binary: BinaryType | null = null;
    private timeout: number;
    private connectionId: string;
    private tcpPort: number;

    constructor(name: string, timeout = 30000, explicitConfig?: any) {
        this.name = name;
        // `explicitConfig` permite conexiones internas que NO viven en
        // dbcube.config.js (p. ej. el config.db de DBCube). El resto resuelve
        // su config por nombre desde dbcube.config.js.
        this.config = explicitConfig ?? this.setConfig(name);
        this.arguments = this.setArguments();
        // daemon.requestTimeoutMs de dbcube.config.js manda sobre el default
        this.timeout = this.config?.daemon?.requestTimeoutMs ?? timeout;
        this.connectionId = `${name}_query_engine_${this.config.type}_${this.config.config.DATABASE ?? ''}_${this.config.config.HOST || this.config.config.URL || 'localhost'}`;
        this.tcpPort = this.generatePort();
    }

    private generatePort(): number {
        // Empezar desde el puerto 9944 y buscar hacia abajo
        return 9944;
    }

    private async findAvailablePort(startPort: number): Promise<number> {
        for (let port = startPort; port >= 9900; port--) {
            if (await this.isPortAvailable(port)) {
                return port;
            }
        }
        throw new Error('No available ports found in range 9900-9944');
    }

    private isPortAvailable(port: number): Promise<boolean> {
        return new Promise((resolve) => {
            const tester = net.createServer();

            tester.once('error', () => resolve(false));
            tester.once('listening', () => {
                tester.close();
                resolve(true);
            });

            tester.listen(port, '127.0.0.1');
        });
    }

    async initializeBinary(): Promise<void> {
        if (!this.binary) {
            this.binary = await Binary.get();
        }
    }

    setArguments() {
        let args = [];
        // "postgres" es alias de "postgresql"; los engines esperan el largo.
        const motor = this.config.type === 'postgres' ? 'postgresql' : this.config.type;
        if (this.config.type == 'sqlite') {
            // Turso (sqlite + URL libsql://): conexión remota, NO archivo local.
            if (this.config.config.URL != null && this.config.config.URL !== '') {
                args = [
                    '--id', 'dbcube-' + this.name,
                    '--database-ref', this.name,
                    '--database', this.config.config.DATABASE ?? '',
                    '--motor', motor,
                    '--url', this.config.config.URL,
                ];
                if (this.config.config.AUTH_TOKEN != null && this.config.config.AUTH_TOKEN !== '') {
                    args.push('--auth-token', this.config.config.AUTH_TOKEN);
                }
            } else {
                args = [
                    '--id', 'dbcube-' + this.name,
                    '--database-ref', this.name,
                    '--database', this.config.config.DATABASE + ".db",
                    '--motor', motor
                ];
            }
        } else {
            args = [
                '--id', 'dbcube-' + this.name,
                '--database-ref', this.name,
                '--database', this.config.config.DATABASE ?? '',
                '--motor', motor
            ];
            // Connection string (Supabase/PlanetScale/Atlas...): si está, aporta
            // host/credenciales/TLS; si no, se pasan los campos sueltos.
            if (this.config.config.URL != null && this.config.config.URL !== '') {
                args.push('--url', this.config.config.URL);
            } else {
                args.push('--host', this.config.config.HOST, '--port', String(this.config.config.PORT));
                // Credenciales opcionales (p. ej. MongoDB local sin auth)
                if (this.config.config.USER != null && this.config.config.USER !== '') {
                    args.push('--user', this.config.config.USER);
                }
                if (this.config.config.PASSWORD != null && this.config.config.PASSWORD !== '') {
                    args.push('--password', this.config.config.PASSWORD);
                }
            }
        }

        // Tuning de pool desde la sección `pool` de dbcube.config.js
        const pool = this.config.pool ?? {};
        if (pool.maxConnections != null) args.push('--max-connections', String(pool.maxConnections));
        if (pool.minConnections != null) args.push('--min-connections', String(pool.minConnections));
        if (pool.acquireTimeoutMs != null) args.push('--acquire-timeout-ms', String(pool.acquireTimeoutMs));
        if (pool.idleTimeoutMs != null) args.push('--idle-timeout-ms', String(pool.idleTimeoutMs));

        return args;
    }

    /** El daemon puede desactivarse por config (daemon.enabled=false) o por env (DBCUBE_DAEMON=0). */
    private daemonEnabled(): boolean {
        const flag = process.env.DBCUBE_DAEMON;
        if (flag === '0' || flag === 'false') return false;
        return this.config?.daemon?.enabled !== false;
    }

    setConfig(name: string) {
        const configInstance = new ConfigClass();

        // Carga automática de .env (cargador propio de DBCube) antes de evaluar
        // la config: el usuario no necesita dotenv ni require("dotenv").
        EnvLoader.load();

        try {
            // En proyectos ESM, dbcube.config.cjs se puede cargar con require()
            // y dbcube.config.js no. Preferimos el .cjs si existe.
            const cjsPath = path.resolve(process.cwd(), 'dbcube.config.cjs');
            const configFilePath = fs.existsSync(cjsPath)
                ? cjsPath
                : path.resolve(process.cwd(), 'dbcube.config.js');
            const requireUrl = typeof __filename !== 'undefined' ? __filename : process.cwd();
            const require = createRequire(requireUrl);
            // Clear require cache to ensure fresh load (safe check for bundled environments)
            if (require.cache && require.resolve) {
                try {
                    delete require.cache[require.resolve(configFilePath)];
                } catch (e) {
                    // Ignore errors in bundled environments
                }
            }
            const configModule = require(configFilePath);
            const configFn = configModule.default || configModule;

            if (typeof configFn === 'function') {
                configFn(configInstance);
            } else {
                console.error('❌ El archivo dbcube.config.js no exporta una función.');
            }
        } catch (error: any) {
            console.error('❌ Error loading config file:', error.message);
            if (error.code === 'MODULE_NOT_FOUND') {
                console.error('❌ Config file not found, please create a dbcube.config.js file');
            }
        }

        return configInstance.getDatabase(name);
    }

    getConfig() {
        return this.config;
    }

    async run(binary: string, args: string[]): Promise<ResponseEngine> {
        // Detectar si es una acción execute de query_engine
        const actionIndex = args.findIndex(arg => arg === '--action');
        const isExecuteAction = actionIndex !== -1 && args[actionIndex + 1] === 'execute';
        const isQueryEngine = binary === 'query_engine';

        if (isQueryEngine && isExecuteAction) {
            // Solo query_engine con execute usa servidor TCP con cola
            return this.executeWithTcpServer(this.argsToCommand(args));
        } else {
            // Para otras acciones, usar método normal
            return this.createProcess(binary, args);
        }
    }

    private argsToCommand(args: string[]): Record<string, any> {
        const command: Record<string, any> = {};
        for (let i = 0; i < args.length; i += 2) {
            if (args[i].startsWith('--')) {
                command[args[i].substring(2)] = args[i + 1];
            }
        }
        return command;
    }

    /** El motor embebido (FFI) es el camino por defecto cuando la librería
     *  nativa está disponible; el daemon TCP queda como fallback y como modo
     *  multi-proceso explícito. */
    private useEmbedded(): boolean {
        return EmbeddedEngine.available();
    }

    /**
     * Executes a DML plan. Embedded engine when available (in-process FFI,
     * no network hop); persistent TCP daemon otherwise.
     * Pass txId to run it inside an active transaction.
     */
    async executeDml(dml: object, txId?: string): Promise<ResponseEngine> {
        if (this.useEmbedded()) {
            return EmbeddedEngine.executeDml(this.connectionId, this.config, dml, txId);
        }
        // El DML viaja como objeto dentro del comando: una sola serialización
        // (el server acepta objeto; el string anidado queda para clientes legacy)
        const command: Record<string, any> = { action: 'execute', dml };
        if (txId) command.tx_id = txId;
        return this.executeWithTcpServer(command);
    }

    /**
     * Atomic batch: N write plans inside one transaction with a single
     * engine round-trip. Falls back to begin/ops/commit over the daemon
     * when the embedded engine is not available.
     */
    async executeBatch(ops: object[]): Promise<ResponseEngine> {
        if (this.useEmbedded()) {
            return EmbeddedEngine.executeBatch(this.connectionId, this.config, ops);
        }
        // Fallback daemon: misma atomicidad, N+2 cruces
        const txId = await this.beginTransaction();
        try {
            const results: any[] = [];
            for (const op of ops) {
                const res = await this.executeDml(op, txId);
                if (res.status !== 200) {
                    throw new Error(String(res.message));
                }
                results.push(res.data);
            }
            await this.commitTransaction(txId);
            return { status: 200, message: 'Batch committed', data: results };
        } catch (error: any) {
            try { await this.rollbackTransaction(txId); } catch { /* secundario */ }
            return { status: 500, message: error?.message ?? String(error), data: null };
        }
    }

    /**
     * Executes raw SQL (or a MongoDB command document) with bound parameters.
     */
    async rawQuery(query: string, params: any[] = [], txId?: string): Promise<ResponseEngine> {
        if (this.useEmbedded()) {
            return EmbeddedEngine.rawQuery(this.connectionId, this.config, query, params, txId);
        }
        const command: Record<string, any> = { action: 'raw', query, params };
        if (txId) command.tx_id = txId;
        return this.executeWithTcpServer(command);
    }

    /** Starts a transaction and returns its id. */
    async beginTransaction(): Promise<string> {
        const res = this.useEmbedded()
            ? await EmbeddedEngine.begin(this.connectionId, this.config)
            : await this.executeWithTcpServer({ action: 'begin' });
        if (res.status !== 200 || !res.data?.tx_id) {
            throw new Error(String(res.message || 'Failed to begin transaction (update the query-engine binary: npx dbcube update)'));
        }
        return res.data.tx_id;
    }

    async commitTransaction(txId: string): Promise<void> {
        const res = this.useEmbedded()
            ? await EmbeddedEngine.commit(this.connectionId, this.config, txId)
            : await this.executeWithTcpServer({ action: 'commit', tx_id: txId });
        if (res.status !== 200) throw new Error(String(res.message || 'Failed to commit transaction'));
    }

    async rollbackTransaction(txId: string): Promise<void> {
        const res = this.useEmbedded()
            ? await EmbeddedEngine.rollback(this.connectionId, this.config, txId)
            : await this.executeWithTcpServer({ action: 'rollback', tx_id: txId });
        if (res.status !== 200) throw new Error(String(res.message || 'Failed to rollback transaction'));
    }

    private async executeWithTcpServer(command: Record<string, any>): Promise<ResponseEngine> {
        // Daemon desactivado: ejecutar one-shot por spawn. Las transacciones
        // requieren el daemon (la TX vive en su memoria entre requests).
        if (!this.daemonEnabled()) {
            if (command.tx_id || ['begin', 'commit', 'rollback'].includes(command.action)) {
                throw new Error('Transactions require daemon mode. Remove daemon.enabled=false from dbcube.config.js (or unset DBCUBE_DAEMON=0).');
            }
            const args: string[] = [];
            for (const [key, value] of Object.entries(command)) {
                args.push(`--${key.replace(/_/g, '-')}`, typeof value === 'string' ? value : JSON.stringify(value));
            }
            return this.createProcess('query_engine', args);
        }

        const serverInfo = globalTcpServers.get(this.connectionId);

        // Si no hay servidor TCP, iniciarlo
        if (!serverInfo || !serverInfo.process || serverInfo.process.killed) {
            await this.startTcpServer();
            // Solo verificar la primera vez
            await this.waitForServerReady();
        }

        const port = globalTcpServers.get(this.connectionId)!.port;
        const socket = await this.acquireSocket(port);
        try {
            const result = await this.executeOnConnection(socket, command);
            this.releaseSocket(socket, false);
            return result;
        } catch (error) {
            // Un socket que falló o quedó con respuesta pendiente no es
            // reutilizable: descartarlo y dejar que el pool crezca de nuevo
            this.releaseSocket(socket, true);
            throw error;
        }
    }

    private poolFor(): SocketPool {
        let pool = socketPools.get(this.connectionId);
        if (!pool) {
            pool = { free: [], total: 0, waiters: [] };
            socketPools.set(this.connectionId, pool);
        }
        return pool;
    }

    private async acquireSocket(port: number): Promise<net.Socket> {
        const pool = this.poolFor();

        // Reusar un socket libre vivo
        while (pool.free.length > 0) {
            const s = pool.free.pop()!;
            if (!s.destroyed) return s;
            pool.total--;
        }

        if (pool.total < CLIENT_POOL_SIZE) {
            pool.total++;
            try {
                return await this.createNewConnection(port);
            } catch (e) {
                pool.total--;
                throw e;
            }
        }

        // Pool lleno: esperar a que se libere uno
        return new Promise<net.Socket>(resolve => pool.waiters.push(resolve));
    }

    private releaseSocket(socket: net.Socket, broken: boolean): void {
        const pool = socketPools.get(this.connectionId);
        if (!pool) { socket.destroy(); return; }

        if (broken || socket.destroyed) {
            pool.total--;
            try { socket.destroy(); } catch { /* ya cerrado */ }
            return;
        }

        const waiter = pool.waiters.shift();
        if (waiter) {
            waiter(socket);
        } else {
            pool.free.push(socket);
        }
    }

    private async waitForServerReady(): Promise<void> {
        const maxRetries = 10;
        const retryDelay = 500; // 500ms entre intentos

        const serverInfo = globalTcpServers.get(this.connectionId);
        if (!serverInfo) {
            throw new Error('Server not found');
        }

        for (let i = 0; i < maxRetries; i++) {
            if (await this.isServerResponding(serverInfo.port)) {
                return;
            }
            await this.sleep(retryDelay);
        }
        throw new Error('TCP server failed to become ready within timeout');
    }

    private async isServerResponding(port: number): Promise<boolean> {
        return new Promise((resolve) => {
            const client = new net.Socket();
            const timeout = setTimeout(() => {
                client.destroy();
                resolve(false);
            }, 1000);

            client.connect(port, '127.0.0.1', () => {
                clearTimeout(timeout);
                client.destroy();
                resolve(true);
            });

            client.on('error', () => {
                clearTimeout(timeout);
                resolve(false);
            });
        });
    }

    private sleep(ms: number): Promise<void> {
        return new Promise(resolve => setTimeout(resolve, ms));
    }

    private getCachedDML(dmlJson: string): any {
        // Buscar en cache primero
        if (queryCache.has(dmlJson)) {
            return queryCache.get(dmlJson);
        }

        // Parse y guardar en cache, desalojando la entrada más vieja si está
        // lleno (Map conserva orden de inserción)
        const parsed = JSON.parse(dmlJson);

        if (queryCache.size >= MAX_CACHE_SIZE) {
            const oldest = queryCache.keys().next().value;
            if (oldest !== undefined) queryCache.delete(oldest);
        }
        queryCache.set(dmlJson, parsed);

        return parsed;
    }

    private async startTcpServer(): Promise<void> {
        await this.initializeBinary();

        if (!this.binary) {
            throw new Error('Binary not initialized');
        }

        // Buscar puerto disponible
        this.tcpPort = await this.findAvailablePort(this.tcpPort);

        return new Promise((resolve, reject) => {
            // Iniciar el query_engine como servidor TCP
            const serverArgs = [...this.arguments, '--action', 'server', '--tcp-port', this.tcpPort.toString()];
            const serverProcess = spawn(this.binary!['query_engine' as keyof BinaryType], serverArgs);

            let started = false;

            const timeout = setTimeout(() => {
                if (!started) {
                    serverProcess.kill();
                    reject(new Error('TCP server startup timeout'));
                }
            }, 15000); // Aumentar timeout a 15 segundos

            serverProcess.stdout.on('data', (data) => {
                const output = data.toString();

                if (output.includes('TCP Server listening on')) {
                    if (!started) {
                        started = true;
                        clearTimeout(timeout);
                        globalTcpServers.set(this.connectionId, {
                            port: this.tcpPort,
                            process: serverProcess
                        });
                        resolve();
                    }
                }
            });

            serverProcess.stderr.on('data', (data) => {
                console.error(`[query_engine TCP Server Error] ${data.toString().trim()}`);
            });

            serverProcess.on('close', (code) => {
                globalTcpServers.delete(this.connectionId);
            });

            serverProcess.on('error', (error) => {
                if (!started) {
                    clearTimeout(timeout);
                    reject(error);
                }
            });
        });
    }

    private async createNewConnection(port: number): Promise<net.Socket> {
        return new Promise((resolve, reject) => {
            const client = new net.Socket();
            client.setNoDelay(true);
            client.setKeepAlive(true, 60000);

            const timeout = setTimeout(() => {
                client.destroy();
                reject(new Error('Connection timeout'));
            }, 5000);

            client.connect(port, '127.0.0.1', () => {
                clearTimeout(timeout);
                resolve(client);
            });

            client.on('error', (error) => {
                clearTimeout(timeout);
                reject(error);
            });
        });
    }

    private async executeOnConnection(connection: net.Socket, command: Record<string, any>): Promise<ResponseEngine> {
        return new Promise((resolve, reject) => {
            let responseBuffer = '';
            let isResolved = false;

            const timeout = setTimeout(() => {
                if (!isResolved) {
                    isResolved = true;
                    connection.removeListener('data', onData);
                    connection.removeListener('error', onError);
                    reject(new Error('Request timeout'));
                }
            }, this.timeout);

            const onData = (data: Buffer) => {
                responseBuffer += data.toString();
                // Framing por línea: el server termina cada respuesta con '\n'.
                // Un regex sobre el buffer parcial dispararía antes de tiempo
                // con respuestas grandes fragmentadas en varios chunks TCP
                // (matchearía hasta un '}' interno y el JSON.parse fallaría).
                let idx: number;
                while ((idx = responseBuffer.indexOf('\n')) !== -1 && !isResolved) {
                    const line = responseBuffer.slice(0, idx);
                    responseBuffer = responseBuffer.slice(idx + 1);
                    const marker = line.indexOf('PROCESS_RESPONSE:');
                    if (marker === -1) continue; // ruido de logs del engine
                    isResolved = true;
                    clearTimeout(timeout);
                    connection.removeListener('data', onData);
                    connection.removeListener('error', onError);

                    try {
                        const response: ProcessResponse = JSON.parse(line.slice(marker + 'PROCESS_RESPONSE:'.length));
                        resolve({
                            status: response.status,
                            message: response.message,
                            data: response.data
                        });
                    } catch (error) {
                        reject(new Error('Failed to parse response'));
                    }
                }
            };

            const onError = (error: Error) => {
                if (!isResolved) {
                    isResolved = true;
                    clearTimeout(timeout);
                    connection.removeListener('data', onData);
                    connection.removeListener('error', onError);
                    reject(error);
                }
            };

            connection.on('data', onData);
            connection.on('error', onError);

            // Enviar comando como JSON delimitado por '\n' (framing del servidor)
            connection.write(JSON.stringify(command) + '\n');
        });
    }

    private async createProcess(binary: string, args: string[]): Promise<ResponseEngine> {
        await this.initializeBinary();

        if (!this.binary) {
            throw new Error('Binary not initialized');
        }

        return new Promise<ResponseEngine>((resolve, reject) => {
            const child = spawn(this.binary![binary as keyof BinaryType], [...this.arguments, ...args]);

            let stdoutBuffer = '';
            let stderrBuffer = '';
            let isResolved = false;

            const timeoutId = setTimeout(() => {
                if (!isResolved) {
                    isResolved = true;
                    child.kill();
                    reject(new Error('Process timeout'));
                }
            }, this.timeout);

            const resolveOnce = (response: ResponseEngine) => {
                if (!isResolved) {
                    isResolved = true;
                    clearTimeout(timeoutId);
                    resolve(response);
                }
            };

            // Framing por línea (la respuesta termina en '\n'): un regex sobre
            // el buffer parcial fallaría con respuestas grandes fragmentadas
            const tryParseLines = (buffer: string): string => {
                let idx: number;
                while ((idx = buffer.indexOf('\n')) !== -1) {
                    const line = buffer.slice(0, idx);
                    buffer = buffer.slice(idx + 1);
                    const marker = line.indexOf('PROCESS_RESPONSE:');
                    if (marker === -1) continue;
                    try {
                        const response: ProcessResponse = JSON.parse(line.slice(marker + 'PROCESS_RESPONSE:'.length));
                        resolveOnce({
                            status: response.status,
                            message: response.message,
                            data: response.data
                        });
                    } catch (error) {
                        resolveOnce({
                            status: 500,
                            message: 'Failed to parse response JSON',
                            data: null
                        });
                    }
                }
                return buffer;
            };

            child.stdout.on('data', (data) => {
                stdoutBuffer = tryParseLines(stdoutBuffer + data.toString());
            });

            child.stderr.on('data', (data) => {
                stderrBuffer = tryParseLines(stderrBuffer + data.toString());
            });

            child.on('close', (code) => {
                clearTimeout(timeoutId);
                if (!isResolved) {
                    resolveOnce({
                        status: code === 0 ? 200 : 500,
                        message: code === 0 ? 'Process completed' : `Process exited with code ${code}`,
                        data: null
                    });
                }
            });

            child.on('error', (error) => {
                clearTimeout(timeoutId);
                if (!isResolved) {
                    resolveOnce({
                        status: 500,
                        message: `Process error: ${error.message}`,
                        data: null
                    });
                }
            });

            child.unref();
        });
    }

    async disconnect(): Promise<ResponseEngine> {
        // Liberar la conexión del motor embebido si existe
        await EmbeddedEngine.disconnect(this.connectionId);

        // Cerrar todos los sockets del pool
        const pool = socketPools.get(this.connectionId);
        if (pool) {
            for (const s of pool.free) {
                try { s.destroy(); } catch { /* ya cerrado */ }
            }
            socketPools.delete(this.connectionId);
        }

        const serverInfo = globalTcpServers.get(this.connectionId);

        if (serverInfo && serverInfo.process && !serverInfo.process.killed) {
            serverInfo.process.kill();
            globalTcpServers.delete(this.connectionId);

            return {
                status: 200,
                message: 'TCP server and connections stopped',
                data: null
            };
        }

        return {
            status: 200,
            message: 'No TCP server to stop',
            data: null
        };
    }
}

export { QueryEngine }