import path from "path";
import * as fs from "fs";
import { Binary } from "./Binary";
import { Config as ConfigClass } from './Config';
import { EnvLoader } from './EnvLoader';
import { spawn } from "child_process";
import { ProcessResponse, ResponseEngine } from "../@types/Engine";
import { BinaryType } from "../@types/Binary";
import { createRequire } from 'module';
import { DaemonClient } from './DaemonClient';

class Engine {
    private name: string;
    private config: any;
    private arguments: any;
    private binary: BinaryType | null = null;
    private timeout: number;
    private daemonFailed = false;

    constructor(name: string, timeout = 30000) {
        this.name = name;
        this.config = this.setConfig(name);
        this.arguments = this.setArguments();
        this.timeout = timeout;
    }

    async initializeBinary(): Promise<void> {
        if (!this.binary) {
            this.binary = await Binary.get();
        }
    }

    /**
     * Returns a connected DaemonClient for this database, or null when
     * daemon mode is disabled/unavailable (then callers use spawn mode).
     */
    private async getDaemon(): Promise<DaemonClient | null> {
        if (this.daemonFailed || !DaemonClient.isEnabled()) return null;
        await this.initializeBinary();
        if (!this.binary) return null;

        const binaryPath = this.binary['query_engine' as keyof BinaryType];
        if (!binaryPath) return null;

        const client = DaemonClient.get(this.name, binaryPath, this.arguments);
        const ok = await client.ensure();
        if (!ok) {
            this.daemonFailed = true; // don't retry on every query
            return null;
        }
        return client;
    }

    /**
     * Executes a DML plan. Uses the persistent daemon (sub-millisecond
     * overhead) when available; falls back to one-shot spawn otherwise.
     */
    async executeDml(dml: object, txId?: string): Promise<ResponseEngine> {
        const daemon = await this.getDaemon();
        if (daemon) {
            try {
                return await daemon.execute(dml, txId);
            } catch (error: any) {
                if (txId) throw error; // a transaction can't change transport mid-flight
                // fall through to spawn mode
            }
        }
        if (txId) {
            throw new Error('Transactions require daemon mode. Make sure the query-engine binary is up to date (npx dbcube update).');
        }
        return this.run('query_engine', ['--action', 'execute', '--dml', JSON.stringify(dml)] as any);
    }

    /**
     * Executes raw SQL (or a MongoDB command document) with bound parameters.
     */
    async rawQuery(query: string, params: any[] = [], txId?: string): Promise<ResponseEngine> {
        const daemon = await this.getDaemon();
        if (daemon) {
            try {
                return await daemon.raw(query, params, txId);
            } catch (error: any) {
                if (txId) throw error;
            }
        }
        if (txId) {
            throw new Error('Transactions require daemon mode. Make sure the query-engine binary is up to date (npx dbcube update).');
        }
        return this.run('query_engine', ['--action', 'raw', '--query', query, '--params', JSON.stringify(params)] as any);
    }

    /** Starts a transaction (daemon mode only). Returns the transaction id. */
    async beginTransaction(): Promise<string> {
        const daemon = await this.getDaemon();
        if (!daemon) {
            throw new Error('Transactions require daemon mode. Make sure the query-engine binary is up to date (npx dbcube update).');
        }
        return daemon.begin();
    }

    async commitTransaction(txId: string): Promise<void> {
        const daemon = await this.getDaemon();
        if (!daemon) throw new Error('Daemon connection lost during transaction');
        return daemon.commit(txId);
    }

    async rollbackTransaction(txId: string): Promise<void> {
        const daemon = await this.getDaemon();
        if (!daemon) throw new Error('Daemon connection lost during transaction');
        return daemon.rollback(txId);
    }

    setArguments() {
        let args = [];
        // Los engines esperan "postgresql"; aceptamos "postgres" en la config
        // como alias y lo normalizamos aquí (schema-engine solo acepta el largo).
        const motor = this.config.type === 'postgres' ? 'postgresql' : this.config.type;
        if (this.config.type == 'sqlite') {
            // Turso (sqlite + URL libsql://): conexión remota, NO archivo local.
            if (this.config.config.URL != null && this.config.config.URL !== '') {
                args = [
                    '--id', 'dbcube-' + this.name,
                    '--database-ref', this.name,
                    '--database', this.config.config.DATABASE ?? '',
                    '--motor', motor,
                    '--url', this.config.config.URL,
                ];
                if (this.config.config.AUTH_TOKEN != null && this.config.config.AUTH_TOKEN !== '') {
                    args.push('--auth-token', this.config.config.AUTH_TOKEN);
                }
            } else {
                args = [
                    '--id', 'dbcube-' + this.name,
                    '--database-ref', this.name,
                    '--database', this.config.config.DATABASE + ".db",
                    '--motor', motor
                ];
            }
        } else {
            args = [
                '--id', 'dbcube-' + this.name,
                '--database-ref', this.name,
                '--database', this.config.config.DATABASE ?? '',
                '--motor', motor
            ];
            // Connection string (Supabase/PlanetScale/Atlas...): si está, aporta
            // host/credenciales/TLS; si no, se pasan los campos sueltos.
            if (this.config.config.URL != null && this.config.config.URL !== '') {
                args.push('--url', this.config.config.URL);
            } else {
                args.push('--host', this.config.config.HOST, '--port', String(this.config.config.PORT));
                if (this.config.config.USER != null && this.config.config.USER !== '') {
                    args.push('--user', this.config.config.USER);
                }
                if (this.config.config.PASSWORD != null && this.config.config.PASSWORD !== '') {
                    args.push('--password', this.config.config.PASSWORD);
                }
            }
        }
        return args;
    }

    setConfig(name: string) {
        const configInstance = new ConfigClass();

        // Carga automática de .env (cargador propio de DBCube): sin dotenv.
        EnvLoader.load();

        try {
            // En proyectos ESM, dbcube.config.cjs se carga con require() y el .js no.
            const cjsPath = path.resolve(process.cwd(), 'dbcube.config.cjs');
            const configFilePath = fs.existsSync(cjsPath)
                ? cjsPath
                : path.resolve(process.cwd(), 'dbcube.config.js');
            // Use __filename for CJS, process.cwd() for ESM
            const requireUrl = typeof __filename !== 'undefined' ? __filename : process.cwd();
            const require = createRequire(requireUrl);
            // Clear require cache to ensure fresh load (safe check for bundled environments)
            if (require.cache && require.resolve) {
                try {
                    delete require.cache[require.resolve(configFilePath)];
                } catch (e) {
                    // Ignore errors in bundled environments
                }
            }
            const configModule = require(configFilePath);
            const configFn = configModule.default || configModule;

            if (typeof configFn === 'function') {
                configFn(configInstance);
            } else {
                console.error('❌ El archivo dbcube.config.js no exporta una función.');
            }
        } catch (error: any) {
            console.error('❌ Error loading config file:', error.message);
            if (error.code === 'MODULE_NOT_FOUND') {
                console.error('❌ Config file not found, please create a dbcube.config.js file');
            }
        }

        return configInstance.getDatabase(name);

    }

    getConfig() {
        return this.config;
    }

    async run(binary: string, args: []) {
        await this.initializeBinary();

        if (!this.binary) {
            throw new Error('Binary not initialized');
        }

        return new Promise<ResponseEngine>((resolve, reject) => {
            const child = spawn(this.binary![binary as keyof BinaryType], [...this.arguments, ...args]);

            let stdoutBuffer = '';
            let stderrBuffer = '';
            let isResolved = false;

            const timeoutId = setTimeout(() => {
                if (!isResolved) {
                    isResolved = true;
                    child.kill();
                    reject(new Error('Process timeout'));
                }
            }, this.timeout);

            const resolveOnce = (response: ResponseEngine) => {
                if (!isResolved) {
                    isResolved = true;
                    clearTimeout(timeoutId);
                    resolve(response);
                }
            };

            // Framing por línea (la respuesta termina en '\n'): un regex sobre
            // el buffer parcial fallaría con respuestas grandes fragmentadas
            const tryParseLines = (buffer: string): string => {
                let idx: number;
                while ((idx = buffer.indexOf('\n')) !== -1) {
                    const line = buffer.slice(0, idx);
                    buffer = buffer.slice(idx + 1);
                    const marker = line.indexOf('PROCESS_RESPONSE:');
                    if (marker === -1) continue;
                    try {
                        const response: ProcessResponse = JSON.parse(line.slice(marker + 'PROCESS_RESPONSE:'.length));
                        resolveOnce({
                            status: response.status,
                            message: response.message,
                            data: response.data
                        });
                    } catch (error) {
                        resolveOnce({
                            status: 500,
                            message: 'Failed to parse response JSON',
                            data: null
                        });
                    }
                }
                return buffer;
            };

            // Solo en modo debug mostramos la salida cruda del engine (println!
            // de progreso/diagnóstico). En uso normal la UI la dan los builders
            // (cajas de resumen), no el ruido del binario.
            const showEngineOutput = process.env.DBCUBE_DEBUG === '1' || process.env.DBCUBE_DEBUG === 'true';

            child.stdout.on('data', (data) => {
                const text = data.toString();
                if (showEngineOutput) {
                    const visible = text.split('\n').filter((l: string) => l.trim() && !l.includes('PROCESS_RESPONSE:')).join('\n');
                    if (visible) console.log(visible);
                }
                stdoutBuffer = tryParseLines(stdoutBuffer + text);
            });

            child.stderr.on('data', (data) => {
                const text = data.toString();
                if (showEngineOutput) {
                    const visible = text.split('\n').filter((l: string) => l.trim() && !l.includes('PROCESS_RESPONSE:')).join('\n');
                    if (visible) console.log(visible);
                }
                stderrBuffer = tryParseLines(stderrBuffer + text);
            });


            child.on('close', (code) => {
                clearTimeout(timeoutId);
                if (!isResolved) {
                    resolveOnce({
                        status: code === 0 ? 200 : 500,
                        message: code === 0 ? 'Process completed' : `Process exited with code ${code}`,
                        data: null
                    });
                }
            });

            child.on('error', (error) => {
                clearTimeout(timeoutId);
                if (!isResolved) {
                    resolveOnce({
                        status: 500,
                        message: `Process error: ${error.message}`,
                        data: null
                    });
                }
            });

            child.unref();
        });
    }
}

export { Engine }