import * as fs from 'fs';
import * as path from 'path';
import { ResponseEngine } from '../@types/Engine';

/**
 * Motor embebido: el query-engine de Rust cargado DENTRO del proceso, en
 * lugar de hablarle por TCP a un daemon. Elimina el round-trip de red por
 * query (~1-1.5ms → ~µs).
 *
 * Dos backends, en orden de preferencia:
 * 1. **Addon napi** (`query-engine-node-<plat>-<arch>.node`): async real —
 *    cada llamada corre en el runtime tokio del addon y resuelve la Promise
 *    vía threadsafe-function, sin ocupar el threadpool de libuv ni
 *    serializar marshaling en el hilo principal (concurrencia plena).
 * 2. **koffi/FFI** (`query-engine-embedded-<plat>-<arch>.dll/.so/.dylib`):
 *    interfaz C pura — el mismo contrato que usarán Python/PHP/Go.
 *
 * - Desactivable con DBCUBE_EMBEDDED=0 (vuelve al daemon TCP).
 * - El daemon sigue siendo el modo correcto cuando varios PROCESOS quieren
 *   compartir pools; embebido es el camino rápido por-proceso.
 */

// Solo afecta al backend koffi (sus llamadas async usan el threadpool de
// libuv). El addon napi no pasa por ahí.
if (!process.env.UV_THREADPOOL_SIZE) {
    process.env.UV_THREADPOOL_SIZE = '16';
}

/** Contrato interno: cada backend resuelve a ResponseEngine.
 *  dml/params viajan como valores JS: el backend napi los pasa nativos
 *  (cero JSON); el backend koffi los serializa una vez. */
interface EngineBackend {
    /** Devuelve el handle de conexión; lanza si falla. */
    connect(cfgJson: string): Promise<number>;
    execute(handle: number, dml: object, txId: string | null): Promise<ResponseEngine>;
    /** Transacción atómica de N escrituras en UNA llamada (begin/commit internos). */
    executeBatch(handle: number, ops: object[]): Promise<ResponseEngine>;
    raw(handle: number, query: string, params: unknown[], txId: string | null): Promise<ResponseEngine>;
    begin(handle: number): Promise<ResponseEngine>;
    commit(handle: number, txId: string): Promise<ResponseEngine>;
    rollback(handle: number, txId: string): Promise<ResponseEngine>;
    disconnect(handle: number): Promise<void>;
}

let backend: EngineBackend | null = null;
let loadFailed = false;

const handles = new Map<string, number>();
const connecting = new Map<string, Promise<number>>();

function platTag(): { plat: string; ext: string; arch: string } {
    const arch = process.arch === 'arm64' ? 'arm64' : 'x64';
    if (process.platform === 'win32') return { plat: 'windows', ext: 'dll', arch };
    if (process.platform === 'darwin') return { plat: 'macos', ext: 'dylib', arch };
    return { plat: 'linux', ext: 'so', arch };
}

function findFile(name: string): string | null {
    const candidates = [
        path.resolve(process.cwd(), '.dbcube', 'bin', name),
        path.resolve(process.cwd(), 'node_modules', '.dbcube', 'bin', name),
    ];
    for (const c of candidates) {
        if (fs.existsSync(c)) return c;
    }
    return null;
}

function ok(data: unknown): ResponseEngine {
    return { status: 200, message: 'OK', data: data as any };
}

function errResp(e: unknown): ResponseEngine {
    const msg = e instanceof Error ? e.message : String(e);
    return { status: 500, message: msg, data: null };
}

// ── Backend 1: addon napi ────────────────────────────────────────────────

function loadNapiBackend(): EngineBackend | null {
    const { plat, arch } = platTag();
    const addonPath = findFile(`query-engine-node-${plat}-${arch}.node`);
    if (!addonPath) return null;

    try {
        // eslint-disable-next-line @typescript-eslint/no-var-requires
        const addon = require(addonPath);
        if (typeof addon.connect !== 'function') return null;

        return {
            async connect(cfgJson) {
                return Number(await addon.connect(cfgJson));
            },
            async execute(handle, dml, txId) {
                try {
                    // dml y filas cruzan como objetos nativos: cero JSON
                    const rows = await addon.execute(handle, dml, txId ?? undefined);
                    return ok(rows);
                } catch (e) { return errResp(e); }
            },
            async executeBatch(handle, ops) {
                try {
                    const results = await addon.executeBatch(handle, ops);
                    return ok(results);
                } catch (e) { return errResp(e); }
            },
            async raw(handle, query, params, txId) {
                try {
                    const rows = await addon.raw(handle, query, params, txId ?? undefined);
                    return ok(rows);
                } catch (e) { return errResp(e); }
            },
            async begin(handle) {
                try {
                    const txId = await addon.begin(handle);
                    return ok({ tx_id: txId });
                } catch (e) { return errResp(e); }
            },
            async commit(_handle, txId) {
                try {
                    await addon.commit(txId);
                    return ok(null);
                } catch (e) { return errResp(e); }
            },
            async rollback(_handle, txId) {
                try {
                    await addon.rollback(txId);
                    return ok(null);
                } catch (e) { return errResp(e); }
            },
            async disconnect(handle) {
                try { addon.disconnect(handle); } catch { /* proceso terminando */ }
            },
        };
    } catch {
        return null;
    }
}

// ── Backend 2: koffi sobre la interfaz C ─────────────────────────────────

function loadKoffiBackend(): EngineBackend | null {
    const { plat, ext, arch } = platTag();
    const libPath = findFile(`query-engine-embedded-${plat}-${arch}.${ext}`);
    if (!libPath) return null;

    try {
        // eslint-disable-next-line @typescript-eslint/no-var-requires
        const koffi = require('koffi');
        const lib = koffi.load(libPath);

        const cConnect = lib.func('dbc_connect', 'void *', ['str']);
        const cExecute = lib.func('dbc_execute', 'void *', ['uint64', 'str', 'str']);
        const cExecuteBatch = lib.func('dbc_execute_batch', 'void *', ['uint64', 'str']);
        const cRaw = lib.func('dbc_raw', 'void *', ['uint64', 'str', 'str', 'str']);
        const cBegin = lib.func('dbc_begin', 'void *', ['uint64']);
        const cCommit = lib.func('dbc_commit', 'void *', ['uint64', 'str']);
        const cRollback = lib.func('dbc_rollback', 'void *', ['uint64', 'str']);
        const cDisconnect = lib.func('dbc_disconnect', 'void *', ['uint64']);
        const cFree = lib.func('dbc_free', 'void', ['void *']);

        const take = (ptr: unknown): ResponseEngine => {
            if (!ptr) return { status: 500, message: 'embedded engine returned null', data: null };
            const s: string = koffi.decode(ptr, 'char', -1);
            cFree(ptr);
            try {
                const r = JSON.parse(s);
                return { status: r.status ?? 500, message: r.message ?? '', data: r.data ?? null };
            } catch (e: any) {
                return { status: 500, message: `Invalid embedded response: ${e.message}`, data: null };
            }
        };

        const call = (fn: any, ...args: unknown[]): Promise<ResponseEngine> =>
            new Promise((resolve, reject) => {
                fn.async(...args, (err: Error | null, ptr: unknown) => {
                    if (err) return reject(err);
                    resolve(take(ptr));
                });
            });

        return {
            async connect(cfgJson) {
                const res = await call(cConnect, cfgJson);
                if (res.status !== 200 || !res.data?.handle) {
                    throw new Error(String(res.message || 'embedded connect failed'));
                }
                return Number(res.data.handle);
            },
            execute: (handle, dml, txId) => call(cExecute, handle, JSON.stringify(dml), txId),
            executeBatch: (handle, ops) => call(cExecuteBatch, handle, JSON.stringify(ops)),
            raw: (handle, query, params, txId) => call(cRaw, handle, query, JSON.stringify(params ?? []), txId),
            begin: (handle) => call(cBegin, handle),
            commit: (handle, txId) => call(cCommit, handle, txId),
            rollback: (handle, txId) => call(cRollback, handle, txId),
            async disconnect(handle) {
                try { await call(cDisconnect, handle); } catch { /* proceso terminando */ }
            },
        };
    } catch {
        return null;
    }
}

function loadBackend(): EngineBackend | null {
    if (backend) return backend;
    if (loadFailed) return null;
    if (process.env.DBCUBE_EMBEDDED === '0' || process.env.DBCUBE_EMBEDDED === 'false') {
        loadFailed = true;
        return null;
    }
    backend = loadNapiBackend() ?? loadKoffiBackend();
    if (!backend) loadFailed = true;
    return backend;
}

// ── API pública (igual que antes) ────────────────────────────────────────

export class EmbeddedEngine {
    /** true si algún backend nativo está disponible en esta instalación. */
    static available(): boolean {
        return loadBackend() !== null;
    }

    private static async handleFor(connectionId: string, config: any): Promise<number> {
        const existing = handles.get(connectionId);
        if (existing) return existing;

        const inFlight = connecting.get(connectionId);
        if (inFlight) return inFlight;

        const promise = (async () => {
            const be = loadBackend();
            if (!be) throw new Error('embedded engine not available');

            const motor = config.type === 'postgres' ? 'postgresql' : config.type;
            // SQLite local añade .db al nombre de archivo; pero Turso (sqlite +
            // URL libsql://) NO es un archivo — el nombre va tal cual (o vacío).
            const isTurso = config.type === 'sqlite' && !!config.config.URL;
            const database = (config.type === 'sqlite' && !isTurso)
                ? `${config.config.DATABASE}.db`
                : config.config.DATABASE;
            const cfg: Record<string, unknown> = {
                databaseRef: connectionId,
                motor,
                database,
                host: config.config.HOST,
                port: config.config.PORT != null ? Number(config.config.PORT) : undefined,
                user: config.config.USER,
                password: config.config.PASSWORD,
                // Connection string (Supabase/PlanetScale/Atlas/Turso). Si está
                // presente, el engine la usa y aplica TLS.
                url: config.config.URL,
                // Auth token de Turso/libSQL.
                authToken: config.config.AUTH_TOKEN,
                maxConnections: config.pool?.maxConnections,
                minConnections: config.pool?.minConnections,
                acquireTimeoutMs: config.pool?.acquireTimeoutMs,
                idleTimeoutMs: config.pool?.idleTimeoutMs,
            };
            const handle = await be.connect(JSON.stringify(cfg));
            handles.set(connectionId, handle);
            return handle;
        })();

        connecting.set(connectionId, promise);
        try {
            return await promise;
        } finally {
            connecting.delete(connectionId);
        }
    }

    static async executeDml(connectionId: string, config: any, dml: object, txId?: string): Promise<ResponseEngine> {
        const be = loadBackend()!;
        const handle = await this.handleFor(connectionId, config);
        return be.execute(handle, dml, txId ?? null);
    }

    static async executeBatch(connectionId: string, config: any, ops: object[]): Promise<ResponseEngine> {
        const be = loadBackend()!;
        const handle = await this.handleFor(connectionId, config);
        return be.executeBatch(handle, ops);
    }

    static async rawQuery(connectionId: string, config: any, query: string, params: any[], txId?: string): Promise<ResponseEngine> {
        const be = loadBackend()!;
        const handle = await this.handleFor(connectionId, config);
        return be.raw(handle, query, params ?? [], txId ?? null);
    }

    static async begin(connectionId: string, config: any): Promise<ResponseEngine> {
        const be = loadBackend()!;
        const handle = await this.handleFor(connectionId, config);
        return be.begin(handle);
    }

    static async commit(connectionId: string, config: any, txId: string): Promise<ResponseEngine> {
        const be = loadBackend()!;
        const handle = await this.handleFor(connectionId, config);
        return be.commit(handle, txId);
    }

    static async rollback(connectionId: string, config: any, txId: string): Promise<ResponseEngine> {
        const be = loadBackend()!;
        const handle = await this.handleFor(connectionId, config);
        return be.rollback(handle, txId);
    }

    static async disconnect(connectionId: string): Promise<void> {
        const be = loadBackend();
        const handle = handles.get(connectionId);
        if (be && handle) {
            handles.delete(connectionId);
            await be.disconnect(handle);
        }
    }
}

export default EmbeddedEngine;
