import { QueryEngine } from './QueryEngine';
import * as path from 'path';
import fs from 'fs';

const rootPath = path.resolve(process.cwd(), '.dbcube');

interface DatabaseConfig {
    name?: string;
    HOST?: string;
    USER?: string;
    PASSWORD?: string;
    DATABASE?: string;
    PORT?: number;
}

interface QueryResult {
    status: 'success' | 'error';
    message: string;
    data: any | null;
}

interface ParametrizedQueryResult {
    query: string;
    parameters: any[];
}

// La base interna de DBCube (computed fields, triggers y schemas registrados)
// es un SQLite en `.dbcube/<database>.db`. Antes la leía un binario aparte
// (sqlite-engine, un proceso por query); ahora va por el MISMO query-engine que
// el resto de consultas SQLite — in-process vía el addon embebido (o el daemon
// como fallback). Un binario menos que compilar/versionar/descargar.
class SQLite {
    private database: string;
    private engine: QueryEngine | null = null;

    constructor(config: DatabaseConfig) {
        this.database = config.DATABASE || 'config';
    }

    /** Ruta del archivo SQLite interno (.dbcube/<database>.db). */
    private dbFilePath(): string {
        return path.join(rootPath, this.database + '.db');
    }

    /** QueryEngine sqlite apuntando al archivo interno, con config explícito
     *  (no vive en dbcube.config.js). La ruta relativa `.dbcube/<db>` deja que
     *  QueryEngine le añada `.db` → `.dbcube/<db>.db`, relativo al CWD. */
    private getEngine(): QueryEngine {
        if (!this.engine) {
            const relativeDb = path.join('.dbcube', this.database).replace(/\\/g, '/');
            this.engine = new QueryEngine(`dbcube-internal-${this.database}`, 30000, {
                type: 'sqlite',
                config: { DATABASE: relativeDb },
            });
        }
        return this.engine;
    }

    async ifExist(): Promise<Boolean> {
        // Crear .dbcube si no existe (no crea el .db: eso lo hace schema-engine)
        if (!fs.existsSync(rootPath)) {
            fs.mkdirSync(rootPath, { recursive: true });
        }
        return fs.existsSync(this.dbFilePath());
    }

    async connect(): Promise<QueryEngine> {
        if (!fs.existsSync(rootPath)) {
            fs.mkdirSync(rootPath, { recursive: true });
        }
        return this.getEngine();
    }

    async disconnect(): Promise<void> {
        // Mantenemos el handle caliente entre llamadas (no hay proceso que matar).
        // El engine embebido reutiliza la conexión por connectionId.
    }

    async query(sqlQuery: string): Promise<QueryResult> {
        return this.queryWithParameters(sqlQuery, []);
    }

    async queryWithParameters(sqlQuery: string, params: any[] = []): Promise<QueryResult> {
        try {
            if (typeof sqlQuery !== 'string') {
                throw new Error('The SQL query must be a string.');
            }
            if (!Array.isArray(params)) {
                throw new Error('Parameters must be an array.');
            }

            const response = await this.getEngine().rawQuery(sqlQuery, params);

            if (response.status !== 200) {
                return { status: 'error', message: response.message || 'Query failed', data: null };
            }
            return { status: 'success', message: 'Query executed successfully', data: response.data };
        } catch (error) {
            return {
                status: 'error',
                message: (error as Error).message || 'An error occurred while executing the query.',
                data: null,
            };
        }
    }

    convertToParameterizedQuery(sql: string): ParametrizedQueryResult {
        const normalizedSql = sql.replace(/\s+/g, ' ').trim();
        
        const baseQueryMatch = normalizedSql.match(/^(.+?)\s+VALUES\s*\(/i);
        if (!baseQueryMatch) {
            throw new Error('No se pudo encontrar la estructura VALUES en la consulta');
        }
        
        const baseQuery = baseQueryMatch[1];
        
        const valuesStartIndex = normalizedSql.toUpperCase().indexOf('VALUES');
        const valuesSection = normalizedSql.substring(valuesStartIndex);
        const valuesMatch = valuesSection.match(/VALUES\s*\((.+)\)\s*;?\s*$/i);
        if (!valuesMatch) {
            throw new Error('No se pudieron extraer los valores de la consulta');
        }
        
        const valuesString = valuesMatch[1];
        
        function parseValues(str: string): any[] {
            const values: any[] = [];
            let currentValue = '';
            let inQuotes = false;
            let quoteChar = '';
            let inCompute = false;
            let computeDepth = 0;
            
            for (let i = 0; i < str.length; i++) {
                const char = str[i];
                const prevChar = str[i - 1];
                
                if (!inQuotes && str.substring(i, i + 8) === '@compute') {
                    inCompute = true;
                }
                
                if (inCompute && char === '(') {
                    computeDepth++;
                } else if (inCompute && char === ')') {
                    computeDepth--;
                    if (computeDepth === 0) {
                        inCompute = false;
                    }
                }
                
                if (!inCompute && (char === '"' || char === "'") && prevChar !== '\\') {
                    if (!inQuotes) {
                        inQuotes = true;
                        quoteChar = char;
                    } else if (char === quoteChar) {
                        if (str[i + 1] === quoteChar) {
                            currentValue += char + char;
                            i++;
                            continue;
                        } else {
                            inQuotes = false;
                            quoteChar = '';
                        }
                    }
                }
                
                if (!inQuotes && !inCompute && char === ',') {
                    values.push(cleanValue(currentValue.trim()));
                    currentValue = '';
                    continue;
                }
                
                currentValue += char;
            }
            
            if (currentValue.trim()) {
                values.push(cleanValue(currentValue.trim()));
            }
            
            return values;
        }
        
        function cleanValue(value: string): any {
            value = value.trim();
            
            if (value.startsWith('@compute')) {
                return value;
            }
            
            if ((value.startsWith('"') && value.endsWith('"')) || 
                (value.startsWith("'") && value.endsWith("'"))) {
                value = value.slice(1, -1);
                value = value.replace(/''/g, "'").replace(/""/g, '"');
            }
            
            return value;
        }
        
        const parameters = parseValues(valuesString);
        const placeholders = parameters.map(() => '?').join(', ');
        const parametrizedQuery = `${baseQuery} VALUES (${placeholders});`;
        
        return {
            query: parametrizedQuery,
            parameters: parameters
        };
    }
}

export const DbConfig = new SQLite({DATABASE: "config"});
export default DbConfig;